    existing = load_comm('mkt-context', 'colossians')
    merge_comm(existing, NEW)
    save_comm('mkt-context', 'colossians', existing)
    for ch in ['1', '2', '3', '4']:
        print(f'  ch {ch}: {len(existing.get(ch, {}))} verses')
